import json, ast
import pandas as pd

# Load business rows
biz_src = var_call_pM5QCuTTQCe59EQYKV7cCIVF
if isinstance(biz_src, str):
    with open(biz_src, 'r', encoding='utf-8') as f:
        biz_rows = json.load(f)
else:
    biz_rows = biz_src

rev_rows = var_call_XpsMbPafIo4AYazIXcEldBqF

biz_df = pd.DataFrame(biz_rows)
rev_df = pd.DataFrame(rev_rows)

# Parse hours stored as stringified python-like list
weekdays = {"Monday","Tuesday","Wednesday","Thursday","Friday"}

def parse_end_time_to_minutes(s):
    s = s.strip()
    if s.lower() == 'open 24 hours':
        return 24*60
    # handle ranges like '3–8PM' without AM/PM on start
    # split on en dash
    parts = s.replace('\u2013','–').split('–')
    if len(parts) != 2:
        return None
    end = parts[1].strip()
    # normalize end time like '9:30PM' or '8PM'
    import re
    m = re.match(r"^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$", end, re.IGNORECASE)
    if not m:
        return None
    hh = int(m.group(1))
    mm = int(m.group(2) or 0)
    ap = m.group(3).upper()
    if ap == 'AM':
        if hh == 12:
            hh = 0
    else:
        if hh != 12:
            hh += 12
    return hh*60 + mm


def has_weekday_after_6pm(hours_str):
    if hours_str is None or hours_str == 'None':
        return False
    try:
        hrs = ast.literal_eval(hours_str)
    except Exception:
        try:
            hrs = json.loads(hours_str)
        except Exception:
            return False
    if not isinstance(hrs, list):
        return False
    for item in hrs:
        if not (isinstance(item, (list, tuple)) and len(item) == 2):
            continue
        day, span = item[0], item[1]
        if day in weekdays:
            if isinstance(span, str) and span.strip().lower() == 'closed':
                continue
            end_min = parse_end_time_to_minutes(str(span))
            if end_min is not None and end_min > 18*60:
                return True
    return False

biz_df['open_after_6_weekday'] = biz_df['hours'].apply(has_weekday_after_6pm)

# Filter open businesses based on state containing 'Open'
if 'state' in biz_df.columns:
    biz_df['is_open'] = biz_df['state'].astype(str).str.contains('Open', case=False, na=False)
else:
    biz_df['is_open'] = True

filtered = biz_df[biz_df['is_open'] & biz_df['open_after_6_weekday']].copy()

# Join with ratings
rev_df['avg_rating'] = rev_df['avg_rating'].astype(float)
rev_df['review_count'] = rev_df['review_count'].astype(int)
merged = filtered.merge(rev_df, on='gmap_id', how='inner')

# Rank by avg_rating desc, tie-break by review_count desc
merged = merged.sort_values(['avg_rating','review_count'], ascending=[False, False])

top5 = merged.head(5)[['name','hours','avg_rating']].to_dict(orient='records')

print('__RESULT__:')
print(json.dumps(top5, ensure_ascii=False))

